module register_with_enable (
    input [7:0] d,
    input clk,
    input en,
    output [7:0] q
);

    reg [7:0] q_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (en) begin
            q_reg <= d;
        end
    end

    assign q = q_reg;

endmodule
